function handleToolCall(toolName: string, args: any): any {
  switch (toolName) {
    case "buscar_ley":
      return buscarLeyes(args.termino, args.materia).slice(0, 10).map((ley: any) => ({
        ley: ley.titulo,
        abreviatura: ley.abreviatura,
        articulo: ley.articulos[0]?.numero,
        contenido: ley.articulos[0]?.contenido?.substring(0, 300),
        materia: ley.materia
      }));
    case "buscar_jurisprudencia":
      return buscarJurisprudencia(args.termino, args.materia).slice(0, 10).map((j: any) => ({
        titulo: j.titulo,
        materia: j.materia,
        tesis: j.tesis.substring(0, 300),
        precedente: j.precedente
      }));
    case "buscar_plantilla":
      return buscarPlantillas(args.termino, args.materia).slice(0, 5).map((p: any) => ({
        nombre: p.nombre,
        tipo: p.tipo,
        materia: p.materia,
        descripcion: p.descripcion
      }));
    case "buscar_glosario":
      const terminos = buscarTermino(args.termino);
      return terminos.slice(0, 5).map((t: any) => ({
        termino: t.termino,
        definicion: t.definicion,
        categoria: t.categoria
      }));
    default:
      return null;
  }
}

